def layer_scan(model, sae_per_layer, seed_sentences):
    """Find which layers have the cleanest operator features."""
    results = {}
    for layer_idx, sae in enumerate(sae_per_layer):
        activations = collect_activations(
            model, sae, seed_sentences, layer=layer_idx
        )
        op_features = find_operator_features(activations)

        # Score: how many operators have clean, specific features?
        clean_ops = sum(
            1 for feats in op_features.values() 
            if len(feats) > 0
        )
        specificity = mean_specificity(op_features, activations)

        results[layer_idx] = {
            'clean_operators': clean_ops,
            'specificity': specificity,
            'feature_ids': op_features
        }

    return results
